import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Instalar Fabric","description":"Una guía paso a paso sobre como instalar Fabric.","frontmatter":{"title":"Instalar Fabric","description":"Una guía paso a paso sobre como instalar Fabric.","authors":["IMB11"],"search":false,"files":[]},"headers":[],"relativePath":"es_es/1.20.4/players/installing-fabric.md","filePath":"versions/1.20.4/translated/es_es/players/installing-fabric.md","lastUpdated":1739538073000}`);var c={name:`es_es/1.20.4/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalar Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalar Fabric”">​</a></h1><p>Esta guía te enseñará sobre como instalar Fabric usando el launcher oficial de Minecraft.</p><p>Para launchers o lanzadores de terceros, deberías consultar su documentación.</p><h2 id="_1-descarga-el-instalador-de-fabric" tabindex="-1">1. Descarga el instalador de Fabric <a class="header-anchor" href="#_1-descarga-el-instalador-de-fabric" aria-label="Permalink to “1. Descarga el instalador de Fabric”">​</a></h2><p>Puedes descargar el instalador de Fabric desde la <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Página web de Fabric</a>.</p><p>Si estás en Windows, descarga el archivo <code>.exe</code> (<code>Download For Windows</code>), ya que este no requiere que Java esté instalado en tu sistema. Este en cambio usa la instalación de Java que viene con el launcher oficial.</p><p>Si estás en macOS o Linux, descarga la versión <code>.jar</code>. En algunas ocasiones, necesitarás instalar Java antes de este paso.</p><h2 id="_2-corre-el-instalador-de-fabric" tabindex="-1">2. Corre el instalador de Fabric <a class="header-anchor" href="#_2-corre-el-instalador-de-fabric" aria-label="Permalink to “2. Corre el instalador de Fabric”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Cierra Minecraft y el Launcher de Minecraft antes de la instalación.</p></div><details class="details custom-block"><summary>Información para usuarios de MacOS</summary><p>En macOS, puede que tengas que hacer clic derecho en el archivo <code>.jar</code> en tu folder de descargas y hacer clic en <code>Abrir</code> para correrlo.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="Instalador de Fabric con &quot;Instalar&quot; remarcado" loading="lazy"></p><p>Cuando aparezca la pregunta &quot;¿Estás seguro de que quieres abrirlo?&quot;, has clic en <code>Abrir</code> de nuevo.</p></details><p>Una vez abierto el instalador, deberías ver una pantalla como la siguiente:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Instalador de Fabric con &quot;Instalar&quot; remarcado" loading="lazy"></p><p>Para instalar Fabric, simplemente escoge tu versión del juego desde el menú deslizador, y cliquea en <code>Instalar</code>.</p><p><strong>Asegurate de que la opción &#39;Crear Perfil&#39; esté escogida.</strong></p><h2 id="_3-¡hemos-terminado" tabindex="-1">3. ¡Hemos terminado! <a class="header-anchor" href="#_3-¡hemos-terminado" aria-label="Permalink to “3. ¡Hemos terminado!”">​</a></h2><p>¡Una vez que la instalación haya terminado, puedes abrir el Launcher de Minecraft y seleccionar el perfil de Fabric desde el menú deslizador en la esquina inferior izquierda y presionar Jugar!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Launcher de Minecraft con el perfil de Fabric seleccionado" loading="lazy"></p><h2 id="siguientes-pasos" tabindex="-1">Siguientes Pasos <a class="header-anchor" href="#siguientes-pasos" aria-label="Permalink to “Siguientes Pasos”">​</a></h2><p>¡Ahora que has instalado Fabric, puedes agregar mods a tu juego! Visita la guía de <a href="./finding-mods">Encontrar Mods Confiables</a> para mayor información.</p><p>Si encuentras problemas tratando de seguir esta guía, puedes solicitar ayuda en el servidor de <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Discord de Fabric</a>, en el canal de <code>#player-support</code>.</p>`,20)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};